(async () => {
  try {
    // パスワード入力欄を取得
    const passwordInput = document.querySelector('input[name="current_password"][type="password"]');

    if (!passwordInput) {
      return { didAction: false, reason: 'パスワード入力フィールドが見つかりませんでした' };
    }

    const password = '{{account_password}}';

    // フォーカス & クリック（視覚的な意味合いは薄いが一応）
    passwordInput.focus();
    passwordInput.click();
    await new Promise(r => setTimeout(r, 200));

    // 値をクリアしてから入力
    passwordInput.value = '';

    // React対応: HTMLInputElementのネイティブsetterを使用
    const setter = Object.getOwnPropertyDescriptor(HTMLInputElement.prototype, 'value').set;
    setter.call(passwordInput, password);
    passwordInput.dispatchEvent(new Event('input', { bubbles: true }));
    passwordInput.dispatchEvent(new Event('change', { bubbles: true }));
    await new Promise(r => setTimeout(r, 200));

    // --- Enterイベントは使わず、確認ボタンをクリックする ---
    // 英語「Confirm」と日本語「確認する」の両方に対応

    // 画面上のボタンを全部取得して「Confirm」または「確認する」と書かれたものを探す
    const buttons = Array.from(document.querySelectorAll('button, [role="button"]'));
    const confirmButton = buttons.find(btn => {
      const text = (btn.textContent || '').trim();
      // 英語と日本語の両方に対応
      return /confirm/i.test(text) || text === '確認する' || text.includes('確認');
    });

    if (!confirmButton) {
      return { didAction: false, reason: '確認ボタン（Confirm/確認する）が見つかりませんでした' };
    }

    // 確認ボタンクリック
    confirmButton.click();

    // 画面遷移が完了するまで待機（プログレスバーが消えるまで）
    const maxWait = 10000; // 最大10秒
    const startTime = Date.now();
    while (Date.now() - startTime < maxWait) {
      // プログレスバーが存在するか確認
      const progressBar = document.querySelector('[role="progressbar"]');
      if (!progressBar) {
        // プログレスバーが消えた = 画面遷移完了
        await new Promise(r => setTimeout(r, 500)); // 念のため少し待つ
        break;
      }
      await new Promise(r => setTimeout(r, 200));
    }

    // 追加の待機（画面が安定するまで）
    await new Promise(r => setTimeout(r, 1000));

    return { didAction: true, reason: 'パスワードを入力して確認ボタンをクリックしました。画面遷移完了まで待機しました。' };
  } catch (e) {
    return { didAction: false, reason: 'エラー: ' + String(e) };
  }
})()

(async () => {
  try {
    // メールアドレス欄を検索（複数の方法を試す）
    let emailElement = null;

    // 方法1: href="/settings/email" のリンクを直接検索
    emailElement = document.querySelector('a[href="/settings/email"]');

    // 方法2: data-testid="pivot" で role="tab" の要素を検索し、テキストに "Email" が含まれるものを探す
    if (!emailElement) {
      const tabs = Array.from(document.querySelectorAll('a[role="tab"][data-testid="pivot"]'));
      emailElement = tabs.find(tab => {
        const text = (tab.textContent || '').trim();
        return text.includes('Email') || text.includes('メール') || text.includes('@');
      });
    }

    // 方法3: テキストで "Email" を含むリンクを検索
    if (!emailElement) {
      const links = Array.from(document.querySelectorAll('a[role="tab"]'));
      emailElement = links.find(link => {
        const text = (link.textContent || '').trim();
        const span = link.querySelector('span');
        const spanText = span ? (span.textContent || '').trim() : '';
        return text.includes('Email') || text.includes('メール') ||
               spanText === 'Email' || spanText === 'メール';
      });
    }

    if (emailElement) {
      // 要素を画面内にスクロール
      emailElement.scrollIntoView({ behavior: 'smooth', block: 'center' });
      await new Promise(r => setTimeout(r, 300));

      // クリック（1回だけ）
      emailElement.click();
      await new Promise(r => setTimeout(r, 500));

      return { didAction: true, reason: 'メールアドレス欄をクリックしました' };
    }

    return { didAction: false, reason: 'メールアドレス欄が見つかりませんでした' };
  } catch (e) {
    return { didAction: false, reason: 'エラー: ' + String(e) };
  }
})();

(async () => {
  try {
    // Update email addressリンクを検索（<a href="/i/flow/add_email">）
    let updateLink = document.querySelector('a[href="/i/flow/add_email"]');

    // テキストで「Update email address」を含むリンクを検索
    if (!updateLink) {
      const links = Array.from(document.querySelectorAll('a[role="link"]'));
      updateLink = links.find(link => {
        const text = (link.textContent || '').trim();
        return text === 'Update email address' || text === 'メールアドレスを更新' || 
               text.includes('Update email') || text.includes('メールアドレスを更新');
      });
    }

    if (updateLink) {
      // 要素を画面内にスクロール
      updateLink.scrollIntoView({ behavior: 'smooth', block: 'center' });
      await new Promise(r => setTimeout(r, 300));

      // クリック
      updateLink.click();
      await new Promise(r => setTimeout(r, 500));

      // マウスイベントも発火（React対応）
      const clickEvent = new MouseEvent('click', {
        bubbles: true,
        cancelable: true,
        view: window
      });
      updateLink.dispatchEvent(clickEvent);
      await new Promise(r => setTimeout(r, 500));

      return { didAction: true, reason: 'Update email addressリンクをクリックしました' };
    }

    return { didAction: false, reason: 'Update email addressリンクが見つかりませんでした' };
  } catch (e) {
    return { didAction: false, reason: 'エラー: ' + String(e) };
  }
})()

(async () => {
  try {
    // パスワード入力欄を検索（複数のname属性に対応）
    // name="current_password" または name="password" のパスワード入力欄を検索
    let passwordInput = document.querySelector('input[name="current_password"][type="password"]');
    if (!passwordInput) {
      passwordInput = document.querySelector('input[name="password"][type="password"]');
    }
    // モーダルダイアログ内のパスワード入力欄も検索
    if (!passwordInput) {
      const modal = document.querySelector('[role="dialog"]');
      if (modal) {
        passwordInput = modal.querySelector('input[type="password"]');
      }
    }

    // パスワード入力欄が存在しない場合はスキップ
    if (!passwordInput) {
      return { didAction: true, reason: 'パスワード入力画面は表示されていません。スキップします。' };
    }

    const password = '{{account_password}}';

    // フォーカス & クリック
    passwordInput.focus();
    passwordInput.click();
    await new Promise(r => setTimeout(r, 200));

    // 値をクリアしてから入力
    passwordInput.value = '';

    // React対応: HTMLInputElementのネイティブsetterを使用
    const setter = Object.getOwnPropertyDescriptor(HTMLInputElement.prototype, 'value').set;
    setter.call(passwordInput, password);
    passwordInput.dispatchEvent(new Event('input', { bubbles: true }));
    passwordInput.dispatchEvent(new Event('change', { bubbles: true }));
    await new Promise(r => setTimeout(r, 200));

    // Nextボタンを探してクリック（モーダル内も検索）
    let nextButton = null;

    // まずモーダル内を検索
    const modal = document.querySelector('[role="dialog"]');
    if (modal) {
      // data-testid="LoginForm_Login_Button" を検索
      nextButton = modal.querySelector('button[data-testid="LoginForm_Login_Button"]');
      if (!nextButton) {
        const modalButtons = Array.from(modal.querySelectorAll('button, [role="button"]'));
        nextButton = modalButtons.find(btn => {
          const text = (btn.textContent || '').trim();
          return text === 'Next' || text === '次へ' || /^next$/i.test(text);
        });
      }
    }

    // モーダル内で見つからない場合は全体を検索
    if (!nextButton) {
      const buttons = Array.from(document.querySelectorAll('button, [role="button"]'));
      nextButton = buttons.find(btn => {
        const text = (btn.textContent || '').trim();
        return text === 'Next' || text === '次へ' || /^next$/i.test(text);
      });
    }

    if (!nextButton) {
      return { didAction: false, reason: 'Nextボタンが見つかりませんでした' };
    }

    // Nextボタンクリック
    nextButton.click();

    // 画面遷移が完了するまで待機（メールアドレス入力欄が表示されるのを待つ）
    const maxWait = 10000; // 最大10秒
    const startTime = Date.now();
    while (Date.now() - startTime < maxWait) {
      // メールアドレス入力欄が表示されているか確認（モーダル内を優先）
      let emailInput = null;
      const currentModal = document.querySelector('[role="dialog"]');
      if (currentModal) {
        emailInput = currentModal.querySelector('input[name="email"][type="email"]');
        if (!emailInput) {
          emailInput = currentModal.querySelector('input[type="email"]');
        }
      }
      if (!emailInput) {
        emailInput = document.querySelector('input[name="email"][type="email"]');
      }
      if (!emailInput) {
        emailInput = document.querySelector('input[type="email"]');
      }

      if (emailInput) {
        // メールアドレス入力欄が表示された = 画面遷移完了
        await new Promise(r => setTimeout(r, 500));
        break;
      }

      // プログレスバーが消えたかも確認
      const progressBar = document.querySelector('[role="progressbar"]');
      if (!progressBar) {
        // プログレスバーが消えたが、メールアドレス入力欄がまだ表示されていない場合は少し待つ
        await new Promise(r => setTimeout(r, 500));
        // 再度メールアドレス入力欄を確認
        const retryModal = document.querySelector('[role="dialog"]');
        if (retryModal) {
          const retryEmailInput = retryModal.querySelector('input[name="email"][type="email"]') || retryModal.querySelector('input[type="email"]');
          if (retryEmailInput) {
            await new Promise(r => setTimeout(r, 500));
            break;
          }
        }
      }

      await new Promise(r => setTimeout(r, 200));
    }

    // 追加の待機（画面が安定するまで）
    await new Promise(r => setTimeout(r, 1000));

    return { didAction: true, reason: 'パスワードを入力してNextボタンをクリックしました。メールアドレス入力画面への遷移完了まで待機しました。' };
  } catch (e) {
    return { didAction: false, reason: 'エラー: ' + String(e) };
  }
})()

(async () => {
  try {
    // メールアドレス入力欄を検索（モーダル内を優先）
    let emailInput = null;

    // まずモーダルダイアログ内を検索
    const modal = document.querySelector('[role="dialog"]');
    if (modal) {
      // name="email" の入力欄を検索
      emailInput = modal.querySelector('input[name="email"][type="email"]');
      if (!emailInput) {
        emailInput = modal.querySelector('input[type="email"]');
      }
    }

    // モーダル内で見つからない場合は全体を検索
    if (!emailInput) {
      emailInput = document.querySelector('input[name="email"][type="email"]');
      if (!emailInput) {
        emailInput = document.querySelector('input[type="email"]');
      }
    }

    // メールアドレス入力欄が存在しない場合はスキップ
    if (!emailInput) {
      return { didAction: true, reason: 'メールアドレス入力欄は表示されていません。スキップします。' };
    }

    const newEmail = '{{new_email}}';

    // new_emailが空文字列または未定義の場合はエラー
    if (!newEmail || newEmail.trim() === '') {
      return { didAction: false, reason: 'new_emailパラメータが空です。メールアドレスを入力してください。' };
    }

    // フォーカス & クリック
    emailInput.focus();
    emailInput.click();
    await new Promise(r => setTimeout(r, 200));

    // 値をクリアしてから入力
    emailInput.value = '';

    // React対応: HTMLInputElementのネイティブsetterを使用
    const setter = Object.getOwnPropertyDescriptor(HTMLInputElement.prototype, 'value').set;
    setter.call(emailInput, newEmail);
    emailInput.dispatchEvent(new Event('input', { bubbles: true }));
    emailInput.dispatchEvent(new Event('change', { bubbles: true }));
    await new Promise(r => setTimeout(r, 200));

    // 入力値が正しく設定されたか確認
    const currentValue = emailInput.value;
    if (currentValue !== newEmail) {
      return { didAction: false, reason: 'メールアドレスの入力に失敗しました。期待値: ' + newEmail + ', 実際の値: ' + currentValue };
    }

    return { didAction: true, reason: '新しいメールアドレスを入力しました: ' + newEmail };
  } catch (e) {
    return { didAction: false, reason: 'エラー: ' + String(e) };
  }
})()

