(async () => {
  const sleep = (ms) => new Promise(resolve => setTimeout(resolve, ms));

  // 1. モーダル（aria-modal="true" の dialog）が出てくるまで待つ
  let modal = null;
  for (let i = 0; i < 25 && !modal; i++) { // 最大 5 秒（25 * 200ms）
    modal = document.querySelector('div[aria-modal="true"][role="dialog"]');
    if (!modal) {
      await sleep(200);
    }
  }

  if (!modal) {
    return { ok: false, error: 'Verification modal (aria-modal=true) not found' };
  }

  // 2. モーダル内から「Verification code」の input を探す
  let input = null;

  // (a) name 属性で直接ヒットさせる（typo も考慮）
  input =
    modal.querySelector('input[name="verfication_code"]') || // 実際の typo
    modal.querySelector('input[name="verification_code"]');

  // (b) label テキストが "Verification code" の input を探す
  if (!input) {
    const labels = Array.from(modal.querySelectorAll('label'));
    const codeLabel = labels.find(label => {
      const text = (label.textContent || '').trim().toLowerCase();
      return text.includes('verification code');
    });
    if (codeLabel) {
      input = codeLabel.querySelector('input[type="text"], input');
    }
  }

  // (c) それでもダメなら、modal 内の text input のうち最初のもの
  if (!input) {
    input =
      modal.querySelector('input[type="text"][name*="code"]') ||
      modal.querySelector('input[type="text"]');
  }

  if (!input) {
    return { ok: false, error: 'Verification code input field not found in modal' };
  }

  // 3. フォーカス & スクロール（視覚的な確認用）
  input.focus();
  input.scrollIntoView({ behavior: 'smooth', block: 'center' });
  await sleep(200);

  // 4. 確認コードを取得（テンプレート変数から）
  const rawCode = '{{verification_code}}';  // テンプレ置換されるのはここだけ
  const code = (rawCode || '').trim();

  // ★ ここをシンプルにする（テンプレ文字列とは比較しない）
  if (!code) {
    return { ok: false, error: 'verification_code is required (empty)' };
  }

  // 5. React 互換の value セット（ネイティブ setter 経由）
  const nativeInputValueSetter =
    Object.getOwnPropertyDescriptor(window.HTMLInputElement.prototype, 'value')?.set;

  if (nativeInputValueSetter) {
    nativeInputValueSetter.call(input, code);
  } else {
    input.value = code;
  }

  // 6. onChange/onInput を発火させる
  input.dispatchEvent(new Event('input', { bubbles: true }));
  input.dispatchEvent(new Event('change', { bubbles: true }));

  // 7. Verify ボタンが有効になるまで少し待つ
  await sleep(500);

  const actualValue = input.value;

  return {
    ok: actualValue === code,
    didAction: true,
    reason: '確認コードを入力しました',
    value: actualValue
  };
})();

(async () => {
  try {
    // Verify/認証ボタンをテキストで検索（英語と日本語の両方に対応）
