        const text = (btn.textContent || '').trim();
        // 英語「Verify」と日本語「認証」「確認」の両方に対応
        return text === 'Verify' || text === '認証' || text === '確認' || 
               text.includes('Verify') || text.includes('認証') || text.includes('確認');
      });
    }

    // モーダル内で見つからない場合は全体を検索
    if (!verifyButton) {
      const buttons = Array.from(document.querySelectorAll('button[role="button"], button[type="button"], [role="button"]'));
      verifyButton = buttons.find(btn => {
        const text = (btn.textContent || '').trim();
        return text === 'Verify' || text === '認証' || text === '確認' || 
               text.includes('Verify') || text.includes('認証') || text.includes('確認');
