(async () => {
  try {
    // エラーメッセージのセレクターを確認
    const errorSelectors = [
      '[role="alert"]',
      '.error',
      '[class*="error" i]',
      '[class*="Error" i]',
      'div[class*="error" i]'
    ];

    let hasError = false;
    let errorText = '';

    for (const selector of errorSelectors) {
      const elements = document.querySelectorAll(selector);
      for (const el of elements) {
        const text = el.textContent || '';
        if (text.trim() && text.length < 500) {
          // エラーメッセージらしいテキストを検出
          if (text.toLowerCase().includes('error') || 
              text.toLowerCase().includes('invalid') || 
              text.toLowerCase().includes('failed') || 
              text.toLowerCase().includes('エラー') || 
              text.toLowerCase().includes('失敗') ||
              text.toLowerCase().includes('incorrect') ||
              text.toLowerCase().includes('wrong')) {
            hasError = true;
            errorText = text.trim();
            break;
          }
        }
      }
      if (hasError) break;
    }

    if (hasError) {
      return {
        didAction: false,
        reason: 'エラーメッセージが検出されました: ' + errorText
      };
    }

    // 成功の確認: ホーム画面（/home）に遷移しているか、または成功メッセージがあるか
    const currentUrl = window.location.href || '';
    const isHomePage = currentUrl.includes('/home') || currentUrl === 'https://x.com/home' || currentUrl === 'https://x.com/';

    // 成功メッセージのセレクターを確認
    const successSelectors = [
      '[class*="success" i]',
      '[class*="Success" i]',
      'div[class*="success" i]',
      '[role="status"]'
    ];

    let hasSuccess = false;
    for (const selector of successSelectors) {
      const elements = document.querySelectorAll(selector);
      if (elements.length > 0) {
        const text = (elements[0].textContent || '').toLowerCase();
        if (text.includes('success') || text.includes('完了') || text.includes('変更') || text.includes('更新')) {
          hasSuccess = true;
          break;
        }
      }
    }

    // ホーム画面に遷移している、または成功メッセージがある場合は成功とみなす
    if (isHomePage || hasSuccess) {
      return {
        didAction: true,
        reason: 'メールアドレス変更が完了しました（ホーム画面に遷移または成功メッセージを確認）'
      };
    }

    // エラーも成功も検出されない場合は、エラーがないとみなして成功とする
    return {
      didAction: true,
      reason: 'エラーメッセージは検出されませんでした（変更完了とみなします）'
    };
  } catch (e) {
    return {
      didAction: false,
      reason: 'エラー確認中にエラーが発生しました: ' + String(e)
    };
  }
})()
